// Deduplication — block repeated Alertmanager firings for the same alert
// Alertmanager re-fires every repeat_interval even without changes.
// We track alertname+namespace+status and drop duplicates within 10 minutes.

const DEDUP_WINDOW_MS = 10 * 60 * 1000; // 10 minutes

const body = $input.first().json;
const alerts = body.alerts || [];
const key = [
  body.commonLabels?.alertname || alerts[0]?.labels?.alertname || 'unknown',
  body.commonLabels?.namespace || alerts[0]?.labels?.namespace || 'unknown',
  body.status || 'firing'
].join(':');

const now = Date.now();
const store = $getWorkflowStaticData('global');

if (!store.dedup) store.dedup = {};

// Clean up old entries
for (const k of Object.keys(store.dedup)) {
  if (now - store.dedup[k] > DEDUP_WINDOW_MS) delete store.dedup[k];
}

if (store.dedup[key]) {
  const ageSeconds = Math.round((now - store.dedup[key]) / 1000);
  console.log(`DEDUP: dropping repeated alert '${key}' (${ageSeconds}s ago)`);
  return []; // drop — returns empty, workflow stops here
}

store.dedup[key] = now;
console.log(`DEDUP: new alert accepted '${key}'`);
return [$input.first()];

